*.shop.example.com {
    upstream web {
        to http://backend
        sticky by cookie PHPSESSID else client_ip
    }
    upstream images { to http://img }

    @img        path /img/*
    @fromimages upstream images
    route @img -> images

    normalize curr {
        from cookie currency
        map USD,usd -> usd
        map EUR     -> eur
        default usd
    }

    tenant {
        from host
        map *.shop.example.com -> shop
        default other
    }

    @us geo country US ES

    cache_key host path {curr} {tenant} {geo} {geo.continent} {geo.region} {sticky} query_allow genre age v1

    header @fromimages X-Origin images

    cache_ttl @us     ttl 10s grace 1m
    cache_ttl default ttl 5s  grace 30s
}
